from pydantic_ai import Tool
from vex import Vex

vex = Vex(api_key="vex_123")

class PricingTool(Tool):
    max_retries = 3

    async def execute(self, *args, **kwargs):
        for attempt in range(self.max_retries):
            try:
                result = await self._call_api(*args, **kwargs)
                if attempt > 0:
                    vex.record_metric("tool_retries", attempt, tags={"tool": "pricing"})
                return result
            except Exception:
                if attempt == self.max_retries - 1:
                    vex.add_violation("TOOL_RETRY_EXHAUSTED", f"Pricing tool failed after {attempt+1} attempts")
                    raise
